const registerForm=document.getElementById("register-form"),registerError=document.getElementById("register-error"),registerSuccess=document.getElementById("register-success");registerForm&&(registerForm.onsubmit=async function(e){e.preventDefault(),registerError.textContent="",registerSuccess.textContent="";const t=new FormData(this),r=t.get("username"),s=t.get("password");if(s===t.get("confirmPassword"))try{const e=await fetch("https://alexokoriengobe.onrender.com/api/auth/register",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:r,password:s})}),t=await e.json();e.ok?(registerSuccess.textContent="Registration successful! You can now log in.",registerForm.reset()):registerError.textContent=t.message||"Registration failed."}catch(e){registerError.textContent="Network error. Please try again."}else registerError.textContent="Passwords do not match."});